    pii_patterns = [
        r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b',
        r'\b\d{3}-?\d{2}-?\d{4}\b'
    ]

    pii_detected = False
    for chunk in stream:
        chunk_text = chunk.content if hasattr(chunk, 'content') else str(chunk)
        for pattern in pii_patterns:
            if re.search(pattern, chunk_text):
                print(f'🚨 PII detected in stream: {pattern}')
