from pydantic_ai import Agent, tool
import json

def audit_tool_calls_for_pii(calls: list):
    pii_keywords = {'email', 'ssn', 'phone', 'address'}
    violations = []

    for call in calls:
        # Check tool arguments
        args = json.dumps(call.get('arguments', {}))
        for keyword in pii_keywords:
            if keyword in args.lower():
                violations.append(f'Tool {call["name"]} args contain PII: {keyword}')

        # Check tool return
        if 'return_value' in call:
            result = json.dumps(call['return_value'])
            for keyword in pii_keywords:
                if keyword in result.lower():
                    violations.append(f'Tool {call["name"]} return contains PII: {keyword}')

    return violations

