from pydantic import BaseModel, field_validator
import re

class PIIFilteredModel(BaseModel):
    @field_validator('*', mode='before')
    @classmethod
    def scrub_pii(cls, v):
        if isinstance(v, str):
            # Redact emails
            v = re.sub(r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b', '[EMAIL]', v)
            # Redact SSNs
            v = re.sub(r'\b\d{3}-?\d{2}-?\d{4}\b', '[SSN]', v)
            # Redact phones
            v = re.sub(r'\b\d{3}[-\.\s]?\d{3}[-\.\s]?\d{4}\b', '[PHONE]', v)
        return v

# Use in agent response models
class AgentResponse(PIIFilteredModel):
    customer_name: str
    contact_info: str
    account_details: str
